import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Page/page-settings.md","filePath":"th-TH/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"th-TH/Page/page-settings.md"};function n(i,t,l,g,s,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings ควบคุม site display, upload page defaults, background images และ admin panel appearance</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>Title ที่แสดงใน browser tab</td></tr><tr><td>Site icon</td><td>Icon เล็กที่แสดงใน browser tab</td></tr><tr><td>ImgBed name</td><td>Name ที่แสดงบน frontend pages</td></tr><tr><td>ImgBed logo</td><td>Logo image ที่แสดงบน frontend pages</td></tr><tr><td>Logo link</td><td>URL ที่เปิดเมื่อคลิก logo หรือ avatar</td></tr><tr><td>Background switch interval</td><td>Rotation interval สำหรับหลาย backgrounds หน่วย milliseconds <code>60000</code> หมายถึง 60 seconds</td></tr><tr><td>Background opacity</td><td>Opacity ของ background image จาก <code>0</code> ถึง <code>1</code> ค่าต่ำจะดูจางกว่า</td></tr><tr><td>Default URL prefix</td><td>Prefix ที่ใช้ตอน generate image links ถ้าว่างจะใช้ current site domain</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>Announcement ที่แสดงด้านบนของ upload page รองรับ HTML</td></tr><tr><td>Default upload channel</td><td>Upload channel ที่เลือกเป็น default บน upload page เลือก Smart Dispatch ได้ด้วย</td></tr><tr><td>Default upload directory</td><td>Default upload directory เช่น <code>/user/</code> ถ้าว่างหรือ <code>/</code> หมายถึง root</td></tr><tr><td>Default naming method</td><td>Strategy สำหรับ generate filename หลัง upload ดูด้านล่าง</td></tr><tr><td>Convert to WebP by default</td><td>Convert images เป็น WebP ก่อน upload</td></tr><tr><td>Enable compression by default</td><td>Compress images ใน browser ก่อน upload</td></tr><tr><td>Default compression threshold</td><td>Compress อัตโนมัติเมื่อ image เกิน size นี้ หน่วย MB</td></tr><tr><td>Default target size</td><td>Target file size หลัง compression หน่วย MB</td></tr><tr><td>Login page background</td><td>Background image สำหรับ user login page</td></tr><tr><td>Upload page background</td><td>Background image สำหรับ upload page</td></tr><tr><td>Footer portal link</td><td>URL ที่เปิดจาก footer portal button</td></tr><tr><td>Hide footer</td><td>เมื่อ enabled จะซ่อน frontend footer</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>Background image สำหรับ admin login page</td></tr><tr><td>Admin background</td><td>Background image สำหรับ admin pages ใช้ image URL เดียวหรือหลาย URLs</td></tr><tr><td>Image loading mode</td><td>Preview loading mode สำหรับ admin file list Original load original images Smart loading prefer thumbnails สำหรับ public images และ originals สำหรับ restricted images</td></tr><tr><td>Thumbnail source</td><td>Service ที่ใช้ generate thumbnails: wsrv.nl, Cloudflare Image Resizing หรือ WordPress Photon ต้อง enable Cloudflare Image Resizing ใน Cloudflare ก่อนเลือก</td></tr><tr><td>Live2D widget</td><td>แสดง Live2D character ใน admin panel</td></tr><tr><td>Firework click effect</td><td>แสดง firework effect เมื่อคลิก page</td></tr><tr><td>Star cursor trail</td><td>แสดง star trail เมื่อขยับ mouse</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background และ admin login background รองรับ formats เหล่านี้:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>ใช้ Bing wallpaper rotation</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Rotate หลาย images</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>ใช้ background image เดียว</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>ใช้ random image API link คุณสามารถ configure Random Image API ของตัวเองใน Other Settings แล้ว paste generated random image link ที่นี่เป็น single-background entry</td></tr></tbody></table><p>Admin background รองรับ image URLs หลาย URLs แยกด้วย English commas ตาม prompt บน page ถ้าว่างจะใช้ default background</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename เช่น <code>1760000000000_cat.png</code></td></tr><tr><td>Prefix only</td><td>เฉพาะ time-random prefix และ extension เช่น <code>1760000000000.png</code></td></tr><tr><td>Original name only</td><td>เก็บ original filename เช่น <code>cat.png</code> ถ้าซ้ำ ImgBed จะเพิ่ม <code>(1)</code>, <code>(2)</code> เป็นต้น</td></tr><tr><td>Short link</td><td>ใช้ 8-character short ID และ extension เช่น <code>a1b2c3d4.png</code></td></tr></tbody></table>',14)])])}const p=e(o,[["render",n]]);export{u as __pageData,p as default};
